-- ╔═══════════════════════════════════════════════════════════════╗\n-- ║       GMod Radio - Entity (Separate Entity Class)             ║\n-- ║            Placeable Radio in the World                       ║\n-- ╚═══════════════════════════════════════════════════════════════╝\n\nENT.Type = \"anim\"\nENT.Base = \"base_gmodentity\"\nENT.Name = \"🎙️ Radio\"\nENT.Author = \"rockymocky309-art\"\nENT.Spawnable = true\nENT.AdminOnly = false\n\nfunction ENT:SetupDataTables()\n    self:NetworkVar(\"Int\", 0, \"CurrentTrack\")\n    self:NetworkVar(\"Bool\", 0, \"IsPlaying\")\n    self:NetworkVar(\"Float\", 0, \"Volume\")\n    self:NetworkVar(\"Float\", 1, \"Time\")\nend\n\nif SERVER then\n    function ENT:Initialize()\n        self:SetModel(\"models/props_lab/monitor01b.mdl\")\n        self:SetSolid(SOLID_VPHYSICS)\n        self:PhysicsInit(SOLID_VPHYSICS)\n        self:SetUseType(SIMPLE_USE)\n        \n        self:SetCurrentTrack(1)\n        self:SetIsPlaying(false)\n        self:SetVolume(0.7)\n        self:SetTime(0)\n        \n        self.nextSync = CurTime() + 0.5\n        self.radioState = \"stopped\"\n        self.startTime = 0\n    end\n    \n    function ENT:Use(activator, caller)\n        if not IsValid(caller) then return end\n        \n        -- Toggle play\n        self:SetIsPlaying(not self:GetIsPlaying())\n        self.radioState = self:GetIsPlaying() and \"playing\" or \"stopped\"\n        \n        if self:GetIsPlaying() then\n            self.startTime = CurTime()\n            self:EmitSound(\"buttons/button9.wav\")\n        else\n            self:EmitSound(\"buttons/button10.wav\")\n        end\n    end\n    \n    function ENT:Think()\n        if self:GetIsPlaying() then\n            local elapsed = CurTime() - self.startTime\n            self:SetTime(elapsed)\n        end\n        \n        -- Auto-next track\n        local currentTrack = RADIO_PLAYLIST[self:GetCurrentTrack()]\n        if currentTrack and self:GetIsPlaying() then\n            if self:GetTime() >= currentTrack.duration then\n                self:NextTrack()\n            end\n        end\n        \n        self:NextThink(CurTime() + 0.1)\n        return true\n    end\n    \n    function ENT:NextTrack()\n        local next = self:GetCurrentTrack() + 1\n        if next > #RADIO_PLAYLIST then\n            next = 1\n        end\n        self:PlayTrack(next)\n    end\n    \n    function ENT:PrevTrack()\n        local prev = self:GetCurrentTrack() - 1\n        if prev < 1 then\n            prev = #RADIO_PLAYLIST\n        end\n        self:PlayTrack(prev)\n    end\n    \n    function ENT:PlayTrack(trackId)\n        if trackId >= 1 and trackId <= #RADIO_PLAYLIST then\n            self:SetCurrentTrack(trackId)\n            self:SetIsPlaying(true)\n            self:SetTime(0)\n            self.startTime = CurTime()\n            self:EmitSound(\"buttons/button9.wav\")\n        end\n    end\n    \n    function ENT:SetRadioVolume(vol)\n        self:SetVolume(math.Clamp(vol, 0, 1))\n    end\n    \n    function ENT:Stop()\n        self:SetIsPlaying(false)\n        self:SetTime(0)\n        self:EmitSound(\"buttons/button10.wav\")\n    end\nelse\n    function ENT:Initialize()\n        self.visualizerBands = {}\n        for i = 1, 32 do\n            self.visualizerBands[i] = 0\n        end\n        self.lastUIUpdate = CurTime()\n    end\n    \n    function ENT:Draw()\n        self:DrawModel()\n        self:DrawScreen()\n    end\n    \n    function ENT:DrawScreen()\n        local pos = self:GetPos()\n        local ang = self:GetAngles()\n        \n        -- Screen offset\n        local screenPos = pos + ang:Forward() * 5 + ang:Right() * 5 + ang:Up() * 30\n        local screenAng = ang + Angle(45, 0, 0)\n        \n        cam.Start3D2D(screenPos, screenAng, 0.05)\n            self:DrawRadioUI()\n        cam.End3D2D()\n    end\n    \n    function ENT:DrawRadioUI()\n        local w, h = 512, 512\n        local centerX, centerY = w / 2, h / 2\n        \n        -- Background\n        surface.SetDrawColor(25, 25, 35, 255)\n        surface.DrawRect(0, 0, w, h)\n        \n        -- Border\n        surface.SetDrawColor(0, 200, 255, 200)\n        surface.DrawOutlinedRect(0, 0, w, h)\n        \n        -- Title\n        surface.SetFont(\"DermaLarge\")\n        surface.SetTextColor(0, 200, 255, 255)\n        surface.SetTextPos(centerX - 80, 20)\n        surface.DrawText(\"🎙️ FM RADIO\")\n        \n        -- Frequency display\n        local track = RADIO_PLAYLIST[self:GetCurrentTrack()]\n        local freq = 87.5 + (self:GetCurrentTrack() - 1) * 2.5\n        surface.SetFont(\"DermaDefault\")\n        surface.SetTextColor(100, 200, 255, 255)\n        surface.SetTextPos(centerX - 40, 60)\n        surface.DrawText(string.format(\"%.1f FM\", freq))\n        \n        -- Track info\n        if track then\n            surface.SetTextColor(200, 200, 200, 255)\n            surface.SetFont(\"DermaLarge\")\n            surface.SetTextPos(centerX - 150, 120)\n            surface.DrawText(track.name)\n            \n            surface.SetFont(\"DermaDefault\")\n            surface.SetTextPos(centerX - 150, 170)\n            surface.DrawText(track.artist)\n            \n            -- Time display\n            local elapsed = math.floor(self:GetTime())\n            local minutes = math.floor(elapsed / 60)\n            local seconds = elapsed % 60\n            surface.SetTextPos(centerX - 60, 220)\n            surface.DrawText(string.format(\"%02d:%02d / %02d:%02d\", \n                minutes, seconds, \n                math.floor(track.duration / 60), \n                track.duration % 60))\n        end\n        \n        -- Visualizer\n        self:DrawVisualizer(centerX - 200, 280, 400, 120)\n        \n        -- Status\n        surface.SetFont(\"DermaLarge\")\n        if self:GetIsPlaying() then\n            surface.SetTextColor(0, 255, 100, 255)\n            surface.SetTextPos(centerX - 40, 420)\n            surface.DrawText(\"▶️ PLAYING\")\n        else\n            surface.SetTextColor(255, 100, 100, 255)\n            surface.SetTextPos(centerX - 40, 420)\n            surface.DrawText(\"⏹️ STOPPED\")\n        end\n        \n        -- Volume bar\n        surface.SetDrawColor(50, 50, 70, 255)\n        surface.DrawRect(centerX - 150, 460, 300, 20)\n        \n        surface.SetDrawColor(0, 200, 255, 255)\n        surface.DrawRect(centerX - 150, 460, 300 * self:GetVolume(), 20)\n        \n        surface.SetFont(\"DermaDefault\")\n        surface.SetTextColor(200, 200, 200, 255)\n        surface.SetTextPos(centerX + 160, 462)\n        surface.DrawText(math.Round(self:GetVolume() * 100) .. \"%\")\n    end\n    \n    function ENT:DrawVisualizer(x, y, w, h)\n        -- Background\n        surface.SetDrawColor(40, 40, 60, 220)\n        surface.DrawRect(x, y, w, h)\n        \n        -- Update visualizer bands\n        local time = CurTime()\n        for i = 1, 32 do\n            local freq = i / 32\n            local intensity = math.sin(time * (freq * 10)) * 0.5 + 0.5\n            if self:GetIsPlaying() then\n                self.visualizerBands[i] = Lerp(0.1, self.visualizerBands[i], intensity)\n            else\n                self.visualizerBands[i] = Lerp(0.05, self.visualizerBands[i], 0)\n            end\n        end\n        \n        -- Draw bands\n        local bars = 32\n        local barWidth = (w - 10) / bars\n        \n        for i = 1, bars do\n            local height = self.visualizerBands[i] * h * 0.8\n            local bx = x + 5 + (i - 1) * barWidth\n            local by = y + h - height\n            \n            -- Color gradient\n            local hue = (i / bars) * 360\n            local r, g, b = HSVToColor(hue, 0.8, 0.9):Unpack()\n            surface.SetDrawColor(r, g, b, 200)\n            surface.DrawRect(bx, by, barWidth - 2, height)\n        end\n    end\nend\n\nfunction ENT:OnRemove()\n    if SERVER then\n        self:Stop()\n    end\nend\n\nrecall(\"gmod_radio_entity\")\n"
